+fn lock_or_recover<T>(mutex: &std::sync::Mutex<T>) -> std::sync::MutexGuard<'_, T> {
+    match mutex.lock() {
+        Ok(guard) => guard,
+        Err(poisoned) => {
+            warn!(
+                target: "frankensearch.fsfs.lifecycle",
+                "poisoned mutex encountered; recovering inner state"
+            );
+            poisoned.into_inner()
+        }
+    }
+}
